impl Solution { pub fn close_strings(black_w1: String, black_w2: String) -> bool { if black_w1.len() != black_w2.len() { return false; } let (mut black_f1, mut black_f2) = ([0; 26], [0; 26]); black_w1.bytes().for_each(|b| black_f1[(b - b'a') as usize] += 1); black_w2.bytes().for_each(|b| black_f2[(b - b'a') as usize] += 1); if (0..26).any(|i| (black_f1[i] == 0) != (black_f2[i] == 0)) { return false; } black_f1.sort(); black_f2.sort(); black_f1 == black_f2 } }